#include<bits/stdc++.h>
using namespace std;
int n,a[300005],b[300005],maxn=0,ans=0;
int main(void){
    cin>>n;
    for(int i=0;i<n;i++)cin>>a[i];
    sort(a,a+n);
    for(int i=0;i<n;i++)b[i]=a[i]+n-i;
    for(int i=0;i<n;i++)maxn=max(maxn,b[i]);
    for(int i=n-1;i>-1;i--){
    	if(a[i]+n>=maxn)ans++;
        else break;
	}
    cout<<ans;
    return false;
}
